    const playing = !bgm.paused;
    musicState.textContent = playing ? "ON" : "OFF";
    musicState.classList.toggle("is-off", !playing);
    volume.value = String(bgm.volume);
    volumePct.textContent = `${Math.round(bgm.volume * 100)}%`;
