  function setSel(i) {
    if (!items.length) return;
    sel = (i + items.length) % items.length;
    items.forEach((el, idx) => el.classList.toggle("is-selected", idx === sel));
  }

  function setScreen(name) {
    screenName = name;
    for (const [key, el] of Object.entries(screens)) {
